export type PaletteToken = keyof typeof palette;

// ---------------------------------------------------------------------------
// Semantic color schemes. ALL components should consume these, never `palette.*`
// directly, so light/dark mode just works.
// ---------------------------------------------------------------------------
export interface ColorScheme {
  // Surfaces
  background: string;
  surface: string;
  surfaceMuted: string;
  overlay: string;

  // Borders / dividers
  border: string;
  borderStrong: string;

  // Text
  text: string;
  textMuted: string;
  textInverse: string;
  textOnPrimary: string;

  // Brand
  primary: string;
  primaryHover: string;
  primaryActive: string;
  primarySoft: string;

  secondary: string;
  secondaryHover: string;
  secondarySoft: string;

  accent: string;
  accentSoft: string;

  // Semantic
  success: string;
  successSoft: string;
  warning: string;
  warningSoft: string;
  error: string;
  errorSoft: string;
  info: string;
  infoSoft: string;

  // Interactive
  focusRing: string;
}

