// ---------------------------------------------------------------------------
// Aggregated theme object for the mobile ThemeProvider.
// ---------------------------------------------------------------------------
export interface Theme {
  mode: ThemeMode;
  colors: ColorScheme;
  fonts: typeof fonts;
  fontWeights: typeof fontWeights;
  type: typeof typeScale;
  spacing: typeof spacing;
  radii: typeof radii;
  shadows: typeof shadows;
  motion: typeof motion;
  zIndex: typeof zIndex;
}

export const buildTheme = (mode: ThemeMode): Theme => ({
  mode,
  colors: schemes[mode],
  fonts,
  fontWeights,
  type: typeScale,
  spacing,
  radii,
  shadows,
  motion,
  zIndex,
});

export const lightTheme = buildTheme('light');
export const darkTheme = buildTheme('dark');

// ---------------------------------------------------------------------------
// CSS-variable generator for the admin (Tailwind reads `var(--color-…)`).
// ---------------------------------------------------------------------------
const kebab = (s: string): string => s.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);

const schemeToCssVars = (scheme: ColorScheme): Record<string, string> => {
  const vars: Record<string, string> = {};
  for (const [key, value] of Object.entries(scheme)) {
    vars[`--color-${kebab(key)}`] = value;
  }
  return vars;
};

export const cssVariables = {
  light: schemeToCssVars(lightScheme),
  dark: schemeToCssVars(darkScheme),
} as const;

/** Render a CSS string suitable for embedding in a global stylesheet. */
export const generateCssVariables = (): string => {
  const block = (selector: string, vars: Record<string, string>): string => {
    const lines = Object.entries(vars)
      .map(([k, v]) => `  ${k}: ${v};`)
      .join('\n');
    return `${selector} {\n${lines}\n}`;
  };
  return [
    block(':root', cssVariables.light),
    block('.dark, [data-theme="dark"]', cssVariables.dark),
  ].join('\n\n');
};
